def convertLazily(circuit: Circuit): fir.Circuit = {
  val lazyModules = LazyList() ++ circuit.components
  val typeAliases: Seq[String] = circuit.typeAliases.map(_.name)
  fir.Circuit(
    fir.NoInfo,
    lazyModules.map(lm => convert(lm, typeAliases)),
